//! TLS 1.2 Key Derivation Tests
//!
//! This module tests the TLS 1.2 key derivation implementation using
//! test vectors generated by Python's cryptography library.

use tls_decryptor::key_derivation::{Tls12KeyDeriver, derive_keys_tls12};
use tls_decryptor::types::{CipherSuite, Direction, TlsVersion};

use super::{hex_to_bytes, load_tls12_test_vectors};

/// Helper function to convert hex string to fixed-size array
fn hex_to_array<const N: usize>(hex: &str) -> [u8; N] {
    let bytes = hex_to_bytes(hex);
    bytes.try_into().expect("Hex string length mismatch")
}

#[test]
fn test_derive_keys_tls12_aes_128_gcm() {
    let vectors = load_tls12_test_vectors();
    let test = &vectors["key_derivation_tests"]["aes_128_gcm"];

    let client_random = hex_to_array::<32>(test["client_random"].as_str().unwrap());
    let server_random = hex_to_array::<32>(test["server_random"].as_str().unwrap());
    let pre_master_secret = hex_to_bytes(test["pre_master_secret"].as_str().unwrap());

    let session_key = derive_keys_tls12(
        &client_random,
        &server_random,
        &pre_master_secret,
        CipherSuite::TlsRsaWithAes128GcmSha256,
    )
    .expect("TLS 1.2 key derivation failed");

    // Verify derived keys
    let expected_client_key = hex_to_bytes(test["client_write_key"].as_str().unwrap());
    let expected_server_key = hex_to_bytes(test["server_write_key"].as_str().unwrap());
    let expected_client_iv = hex_to_bytes(test["client_write_iv"].as_str().unwrap());
    let expected_server_iv = hex_to_bytes(test["server_write_iv"].as_str().unwrap());

    assert_eq!(
        session_key.get_write_key(Direction::ClientToServer),
        &expected_client_key,
        "Client write key mismatch"
    );
    assert_eq!(
        session_key.get_write_key(Direction::ServerToClient),
        &expected_server_key,
        "Server write key mismatch"
    );
    assert_eq!(
        session_key.get_write_iv(Direction::ClientToServer),
        &expected_client_iv,
        "Client write IV mismatch"
    );
    assert_eq!(
        session_key.get_write_iv(Direction::ServerToClient),
        &expected_server_iv,
        "Server write IV mismatch"
    );
    assert_eq!(session_key.version, TlsVersion::Tls12);
    assert_eq!(
        session_key.cipher_suite,
        CipherSuite::TlsRsaWithAes128GcmSha256
    );
}

